// MARK: - Password Hashing Service

class PasswordHashingService {
    
    // Salt length in bytes
    private static let saltLength = 32
    
    // Number of PBKDF2 iterations (minimum recommended for security)
    private static let pbkdf2Iterations: UInt32 = 100_000
    
    // Derived key length in bytes (256-bit)
    private static let derivedKeyLength = 32
    
    // MARK: - Generate Cryptographically Secure Salt
    
    static func generateSalt() -> Data? {
        var salt = Data(count: saltLength)
        let result = salt.withUnsafeMutableBytes { bufferPointer in
            SecRandomCopyBytes(kSecRandomDefault, saltLength, bufferPointer.baseAddress!)
        }
        guard result == errSecSuccess else {
            return nil
        }
        return salt
    }
    
    // MARK: - PBKDF2 Hashing with HMAC-SHA256
    
    static func hashPassword(_ password: String, salt: Data) -> Data? {
        guard let passwordData = password.data(using: .utf8) else {
            return nil
        }
        
        var derivedKey = Data(count: derivedKeyLength)
        
        let status = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            salt.withUnsafeBytes { saltBytes in
                passwordData.withUnsafeBytes { passwordBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        passwordData.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                        pbkdf2Iterations,
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        derivedKeyLength
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            return nil
        }
        
        return derivedKey
    }
    
    // MARK: - Constant-Time Comparison to Prevent Timing Attacks
    
    static func constantTimeCompare(_ a: Data, _ b: Data) -> Bool {
        guard a.count == b.count else {
            return false
        }
        
        var result: UInt8 = 0
        for i in 0..<a.count {
            result |= a[i] ^ b[i]
        }
        
        return result == 0
    }
}

