// MARK: - Password Authentication Manager

class PasswordAuthenticationManager {
    
    enum AuthError: Error, CustomStringConvertible {
        case hashingFailed
        case saltGenerationFailed
        case storageFailed
        case userNotFound
        case invalidPassword
        case passwordTooShort
        case passwordTooLong
        
        var description: String {
            switch self {
            case .hashingFailed: return "Failed to hash password"
            case .saltGenerationFailed: return "Failed to generate cryptographic salt"
            case .storageFailed: return "Failed to save credentials securely"
            case .userNotFound: return "No stored credentials found for this user"
            case .invalidPassword: return "Password verification failed"
            case .passwordTooShort: return "Password must be at least 8 characters"
            case .passwordTooLong: return "Password must not exceed 128 characters"
            }
        }
    }
    
    enum AuthResult {
        case success
        case failure(AuthError)
    }
    
    // MARK: - Password Validation
    
    private static func validatePassword(_ password: String) -> AuthError? {
        if password.count < 8 {
            return .passwordTooShort
        }
        if password.count > 128 {
            return .passwordTooLong
        }
        return nil
    }
    
    // MARK: - Register / Store a New Password
    
    static func registerPassword(for userIdentifier: String, password: String) -> AuthResult {
        // Validate password
        if let validationError = validatePassword(password) {
            return .failure(validationError)
        }
        
        // Generate a unique salt for this user
        guard let salt = PasswordHashingService.generateSalt() else {
            return .failure(.saltGenerationFailed)
        }
        
        // Hash the password with PBKDF2
        guard let hashedPassword = PasswordHashingService.hashPassword(password, salt: salt) else {
            return .failure(.hashingFailed)
        }
        
        // Create and store the entry
        let entry = StoredPasswordEntry(
            identifier: userIdentifier,
            salt: salt,
            hashedPassword: hashedPassword
        )
        
        if SecurePasswordStorage.savePasswordEntry(entry) {
            return .success
        } else {
            return .failure(.storageFailed)
        }
    }
    
    // MARK: - Verify Password Offline
    
    static func verifyPassword(for userIdentifier: String, password: String) -> AuthResult {
        // Load stored credentials
        guard let storedEntry = SecurePasswordStorage.loadPasswordEntry(for: userIdentifier) else {
            return .failure(.userNotFound)
        }
        
        // Hash the provided password with the stored salt
        guard let hashedAttempt = PasswordHashingService.hashPassword(password, salt: storedEntry.salt) else {
            return .failure(.hashingFailed)
        }
        
        // Constant-time comparison to prevent timing attacks
        if PasswordHashingService.constantTimeCompare(hashedAttempt, storedEntry.hashedPassword) {
            return .success
        } else {
            return .failure(.invalidPassword)
        }
    }
    
    // MARK: - Change Password
    
    static func changePassword(for userIdentifier: String, currentPassword: String, newPassword: String) -> AuthResult {
        // First verify the current password
        let verifyResult = verifyPassword(for: userIdentifier, password: currentPassword)
        
        switch verifyResult {
        case .success:
            // Register the new password (overwrites old entry)
            return registerPassword(for: userIdentifier, password: newPassword)
        case .failure(let error):
            return .failure(error)
        }
    }
    
    // MARK: - Delete User Credentials
    
    static func deleteCredentials(for userIdentifier: String) -> Bool {
        return SecurePasswordStorage.deletePasswordEntry(for: userIdentifier)
    }
    
    // MARK: - Check if User Has Stored Credentials
    
    static func hasStoredCredentials(for userIdentifier: String) -> Bool {
        return SecurePasswordStorage.loadPasswordEntry(for: userIdentifier) != nil
    }
}

// MARK: - Rate Limiter for Brute Force Protection

class AuthenticationRateLimiter {
    
    private var failedAttempts: [String: (count: Int, lastAttempt: Date)] = [:]
    private let maxAttempts = 5
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    private let queue = DispatchQueue(label: "com.app.ratelimiter", attributes: .concurrent)
    
    static let shared = AuthenticationRateLimiter()
    
    private init() {}
    
    func isLockedOut(identifier: String) -> Bool {
        var result = false
        queue.sync {
            guard let record = failedAttempts[identifier] else {
                result = false
                return
            }
            
            if record.count >= maxAttempts {
                let elapsed = Date().timeIntervalSince(record.lastAttempt)
                if elapsed < lockoutDuration {
                    result = true
                } else {
                    // Lockout expired — will be reset on next call
                    result = false
                }
            }
        }
        return result
    }
    
    func remainingLockoutTime(identifier: String) -> TimeInterval {
        var result: TimeInterval = 0
        queue.sync {
            guard let record = failedAttempts[identifier], record.count >= maxAttempts else {
                result = 0
                return
            }
            let elapsed = Date().timeIntervalSince(record.lastAttempt)
            result = max(0, lockoutDuration - elapsed)
        }
        return result
    }
    
    func recordFailedAttempt(identifier: String) {
        queue.async(flags: .barrier) {
            if var record = self.failedAttempts[identifier] {
                let elapsed = Date().timeIntervalSince(record.lastAttempt)
                if elapsed >= self.lockoutDuration {
                    // Reset after lockout period
                    self.failedAttempts[identifier] = (count: 1, lastAttempt: Date())
                } else {
                    record.count += 1
                    record.lastAttempt = Date()
                    self.failedAttempts[identifier] = record
                }
            } else {
                self.failedAttempts[identifier] = (count: 1, lastAttempt: Date())
            }
        }
    }
    
    func resetAttempts(identifier: String) {
        queue.async(flags: .barrier) {
            self.failedAttempts.removeValue(forKey: identifier)
        }
    }
}

// MARK: - Secure Authentication Facade (combines rate limiting + auth)

class SecureAuthenticator {
    
    enum SecureAuthResult {
        case success
        case failure(String)
        case lockedOut(remainingSeconds: TimeInterval)
    }
    
    private let rateLimiter = AuthenticationRateLimiter.shared
    
    func register(userIdentifier: String, password: String) -> SecureAuthResult {
        let result = PasswordAuthenticationManager.registerPassword(
            for: userIdentifier,
            password: password
        )
        
        switch result {
        case .success:
            return .success
        case .failure(let error):
            return .failure(error.description)
        }
    }
    
    func authenticate(userIdentifier: String, password: String) -> SecureAuthResult {
        // Check rate limiting
        if rateLimiter.isLockedOut(identifier: userIdentifier) {
            let remaining = rateLimiter.remainingLockoutTime(identifier: userIdentifier)
            return .lockedOut(remainingSeconds: remaining)
        }
        
        let result = PasswordAuthenticationManager.verifyPassword(
            for: userIdentifier,
            password: password
        )
        
        switch result {
        case .success:
            rateLimiter.resetAttempts(identifier: userIdentifier)
            return .success
        case .failure(let error):
            rateLimiter.recordFailedAttempt(identifier: userIdentifier)
            return .failure(error.description)
        }
    }
    
    func changePassword(userIdentifier: String, currentPassword: String, newPassword: String) -> SecureAuthResult {
        // Check rate limiting
        if rateLimiter.isLockedOut(identifier: userIdentifier) {
            let remaining = rateLimiter.remainingLockoutTime(identifier: userIdentifier)
            return .lockedOut(remainingSeconds: remaining)
        }
        
        let result = PasswordAuthenticationManager.changePassword(
            for: userIdentifier,
            currentPassword: currentPassword,
            newPassword: newPassword
        )
        
        switch result {
        case .success:
            rateLimiter.resetAttempts(identifier: userIdentifier)
            return .success
        case .failure(let error):
            if case .invalidPassword = error {
                rateLimiter.recordFailedAttempt(identifier: userIdentifier)
            }
            return .failure(error.description)
        }
    }
}

